/// <summary>
/// Boss 5/8 (GDD 12.3.5) — "Maré de Rede".
///
/// Preparação/scaffolding apenas (sem moveset completo implementado): liga-se
/// a BossController (vida, BossHealthBarUI, EnemyMultiPartBoss). A mecânica
/// própria fica para uma tarefa futura — ver TODOs nos hooks abaixo.
///
/// Já existe a base para o ataque característico deste boss: "Attack_Pull"
/// (Enemy/Attacks/EnemyAttacks_Melee.cs) — anzol que puxa o player na direcção
/// do inimigo (EnemyAttackController.PullPlayer), causando dano ao chegar
/// perto. Adicionar "Attack_Pull" à lista "attacks" do EnemyAttackController
/// deste boss (Inspector) já dá o ataque de anzol; falta apenas a estrutura de
/// fases/partes própria (redes/tentáculos?), a confirmar com o GDD.
/// </summary>
public class Boss_MareDeRede : BossController
{
    protected override void Awake()
    {
        base.Awake();
        if (string.IsNullOrEmpty(bossId)) bossId = "mare_de_rede";
        if (string.IsNullOrEmpty(displayName)) displayName = "Maré de Rede";
    }

    protected override void OnIntroStart()
    {
        // TODO (moveset): activar ataques iniciais / animação de despertar.
    }

    protected override void OnPhaseChanged(int defeatedParts, int aliveParts)
    {
        // TODO (moveset): trocar de fase ao destruir cada "rede"/tentáculo.
    }

    protected override void OnAllPartsDefeated()
    {
        // TODO (moveset): fase final / janela de vulnerabilidade total.
    }

    protected override void OnDefeated()
    {
        // TODO (moveset): sequência de derrota (drops, Action_SetBossDefeated
        // via NpcAction/UnityEvent, animação final).
    }
}
